      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');

let projects = [];

function createProject(name) {
  const project = { id: randomUUID(), name };
  projects.push(project);
  return project;
}

function getAllProjects() {
  return projects;
}

module.exports = {
  createProject,
  getAllProjects,
};
