      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const { sendError } = require('../../lib/errors');
const taskService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { title } = req.body;
  if (!title) return sendError(res, 400, 'INVALID_TITLE', 'Title is required');

  const projectId = req.params.projectId;
  const task = taskService.createTask(projectId, title);
  if (!task) return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');

  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const status = req.query.status;
  const tasks = taskService.getTasksByProject(projectId, status);
  if (!tasks) return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');

  res.json({ tasks });
});

module.exports = router;
