      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projectService = require('../projects/service');

let tasks = [];

function createTask(projectId, title) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) return null;

  const task = { id: randomUUID(), projectId, title, status: 'todo' };
  tasks.push(task);
  return task;
}

function getTasksByProject(projectId, status) {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) return null;

  let filteredTasks = tasks.filter(t => t.projectId === projectId);
  if (status) {
    filteredTasks = filteredTasks.filter(t => t.status === status);
  }
  return filteredTasks;
}

module.exports = {
  createTask,
  getTasksByProject,
};
